sql:
SELECT device_id, value
FROM operational_data
WHERE timestamp >= '2023-01-01 00:00:00' AND timestamp < '2023-01-02 00:00:00';

SELECT AVG(value) AS average_value
FROM constant_data
WHERE device_id = 0;

SELECT device_id, AVG(value) AS average_value
FROM operational_data
GROUP BY device_id;

external_knowledge:
- 'Top 5 devices' refers to the 5 devices with the highest number of data points; 
- 'Detailed information' includes device ID, device name, number of data points, access count, last access time, user ID, action, and audit time; 
- 'Latest audit logs' refers to the most recent audit log entry for each device.

